| MCP:AQQTGW | const Mock = require('mockjs')
| MCP:AQQTGW | const { param2Obj } = require('./utils')
| MCP:AQQTGW | 
| MCP:AQQTGW | const user = require('./user')
| MCP:AQQTGW | const table = require('./table')
| MCP:AQQTGW | 
| MCP:AQQTGW | const mocks = [...user, ...table]
| MCP:AQQTGW | 
| MCP:AQQTGW | // for front mock
| MCP:AQQTGW | // please use it cautiously, it will redefine XMLHttpRequest,
| MCP:AQQTGW | // which will cause many of your third-party libraries to be invalidated(like progress event).
| MCP:AQQTGW | function mockXHR() {
| MCP:AQQTGW |   // mock patch
| MCP:AQQTGW |   // https://github.com/nuysoft/Mock/issues/300
| MCP:AQQTGW |   Mock.XHR.prototype.proxy_send = Mock.XHR.prototype.send
| MCP:AQQTGW |   Mock.XHR.prototype.send = function () {
| MCP:AQQTGW |     if (this.custom.xhr) {
| MCP:AQQTGW |       this.custom.xhr.withCredentials = this.withCredentials || false
| MCP:AQQTGW | 
| MCP:AQQTGW |       if (this.responseType) {
| MCP:AQQTGW |         this.custom.xhr.responseType = this.responseType
| MCP:AQQTGW |       }
| MCP:AQQTGW |     }
| MCP:AQQTGW |     this.proxy_send(...arguments)
| MCP:AQQTGW |   }
| MCP:AQQTGW | 
| MCP:AQQTGW |   function XHR2ExpressReqWrap(respond) {
| MCP:AQQTGW |     return function (options) {
| MCP:AQQTGW |       let result = null
| MCP:AQQTGW |       if (respond instanceof Function) {
| MCP:AQQTGW |         const { body, type, url } = options
| MCP:AQQTGW |         // https://expressjs.com/en/4x/api.html#req
| MCP:AQQTGW |         result = respond({
| MCP:AQQTGW |           method: type,
| MCP:AQQTGW |           body: JSON.parse(body),
| MCP:AQQTGW |           query: param2Obj(url),
| MCP:AQQTGW |         })
| MCP:AQQTGW |       } else {
| MCP:AQQTGW |         result = respond
| MCP:AQQTGW |       }
| MCP:AQQTGW |       return Mock.mock(result)
| MCP:AQQTGW |     }
| MCP:AQQTGW |   }
| MCP:AQQTGW | 
| MCP:AQQTGW |   for (const i of mocks) {
| MCP:AQQTGW |     Mock.mock(
| MCP:AQQTGW |       new RegExp(i.url),
| MCP:AQQTGW |       i.type || 'get',
| MCP:AQQTGW |       XHR2ExpressReqWrap(i.response)
| MCP:AQQTGW |     )
| MCP:AQQTGW |   }
| MCP:AQQTGW | }
| MCP:AQQTGW | 
| MCP:AQQTGW | module.exports = {
| MCP:AQQTGW |   mocks,
| MCP:AQQTGW |   mockXHR,
| MCP:AQQTGW | }
